const results = $json.results || [];
const hotelName = $('Read Hotels').item.json.hotel_name;
const parsed = [];
const seenContent = new Set();

// Only exact Mövenpick Du Lac Tunis URLs
const correctHotelUrls = [
  'movenpick-du-lac-tunis',
  'Movenpick_Hotel_Du_Lac_Tunis'
];

// Explicitly wrong hotels to exclude
const wrongHotelUrls = [
  'studio-cosy-au-lac',
  'Hotel_Lac_Leman',
  'HotelsList',
  'Hotel_Feature',
  'movenpick-gammarth'
];

results.forEach((r, i) => {
  const content = r.content || '';
  const url = r.url || '';

  // Must be a review page
  const isActualReview = 
    url.includes('booking.com/reviews') ||
    url.includes('booking.com/reviewlist') ||
    url.includes('tripadvisor.com/Hotel_Review-') ||
    url.includes('tripadvisor.com/ShowUserReviews');

  if (!isActualReview) return;
  if (content.length < 20) return;

  // Must be correct hotel URL
  const isCorrectHotel = correctHotelUrls.some(k => url.includes(k));
  if (!isCorrectHotel) return;

  // Must not be wrong hotel
  const isWrongHotel = wrongHotelUrls.some(k => url.includes(k));
  if (isWrongHotel) return;

  let platform = 'Web';
  if (url.includes('booking.com')) platform = 'Booking.com';
  else if (url.includes('tripadvisor.com')) platform = 'TripAdvisor Web';

  const blocks = content
    .split(/(?=Stayed in [A-Z][a-z]+ \d{4})/g)
    .filter(b => b.trim().length > 20);

  const blocksToProcess = blocks.length > 1 ? blocks : [content];

  blocksToProcess.forEach((block, j) => {
    const skipPatterns = [
      'Start of dialog content',
      'Each review score is between',
      'How guest reviews work',
      'Real guests. Real stays',
      'Score breakdown',
      'verified reviews',
      'All content should be genuine',
      'Booking.com property partners',
      'Respect the privacy of others',
      'opinions expressed in contributions',
      'There are no comments available',
      'no comments available'
    ];
    if (skipPatterns.some(p => block.includes(p))) return;

    const ratingMatch = block.match(/\b(10|[0-9]\.[0-9])\b/);
    const rating = ratingMatch ? parseFloat(ratingMatch[1]) : null;

    let reviewer = 'Anonymous';
    const nameMatch1 = block.match(/^([A-Z][a-zA-Z\s]{1,25})\n\s*[A-Z][a-z]+\s*\n\s*\d+ review/m);
    const nameMatch2 = block.match(/Reviewed:.*?\n\s*([A-Z][a-zA-Z\s]{1,25})\n/);
    const nameMatch3 = block.match(/\n([A-Z][a-z]{2,15})\n/);
    if (nameMatch1) reviewer = nameMatch1[1].split('\n')[0].trim();
    else if (nameMatch2) reviewer = nameMatch2[1].split('\n')[0].trim();
    else if (nameMatch3) reviewer = nameMatch3[1].split('\n')[0].trim();
    reviewer = reviewer.replace(/\n.*/s, '').replace(/\s{2,}/g, ' ').trim();

    const dateMatch = block.match(/Stayed in ([A-Z][a-z]+ \d{4})/);
    const reviewDate = dateMatch ? dateMatch[1] : (r.published_date || new Date().toISOString());

    const quoteMatch = block.match(/"([^"]{10,})"/g);
    let reviewText = '';
    if (quoteMatch) {
      reviewText = quoteMatch.map(q => q.replace(/"/g, '').trim()).join(' ');
    }

    if (!reviewText || reviewText.length < 10) {
      const lines = block.split('\n')
        .map(l => l.trim())
        .filter(l =>
          l.length > 20 &&
          !l.match(/^\d+ reviews?$/) &&
          !l.match(/^[A-Z][a-z]+$/) &&
          !l.match(/^\+/) &&
          !l.match(/^Stayed in/) &&
          !l.match(/^Reviewed:/) &&
          !l.match(/^Submitted/) &&
          !l.match(/^\d+\.\s+/) &&
          !l.includes('no comments available') &&
          !l.includes('dialog content')
        );
      reviewText = lines.join(' ').substring(0, 600);
    }

    reviewText = reviewText
      .replace(/^[A-Z][a-zA-Z\s]+ \d+ [Rr]eviews?\s*/g, '')
      .replace(/^\d+ helpful votes?\s*/g, '')
      .replace(/^• Submitted from a mobile device\s*/g, '')
      .replace(/\b\d+ helpful votes?\b/g, '')
      .replace(/•\s+[^•\n]{1,50}(?=•|$)/g, '')
      .replace(/\+\s+•[^\n]+/g, '')
      .replace(/✨/g, '')
      .replace(/🌟/g, '')
      .replace(/👌/g, '')
      .replace(/\[\.\.\.\]/g, '')
      .replace(/\d+\.\s+Hotel reviews homepage→.*/s, '')
      .replace(/\d+\.\s+Tunisia hotel reviews→.*/s, '')
      .replace(/\d+\.\s+Tunis hotel reviews→.*/s, '')
      .replace(/Rue du Lac.*/s, '')
      .replace(/See the hotel.*/s, '')
      .replace(/Write a review.*/s, '')
      .replace(/\d+ helpful votes/g, '')
      .replace(/\s{2,}/g, ' ')
      .trim()
      .substring(0, 600);

    // Skip meaningless review text
    const meaninglessPatterns = [
      /^\w+\s+\d+\s+[Rr]eviews?$/,
      /^#ERROR!/,
      /^[A-Z][a-z]+\s+\d+\s+[A-Z][a-z]+$/
    ];
    if (meaninglessPatterns.some(p => p.test(reviewText.trim()))) return;

    const finalSkip = [
      'Start of dialog content',
      'Each review score is between',
      'no comments available',
      'How guest reviews work',
      'Real guests',
      'All content should be genuine',
      'Booking.com property partners',
      'opinions expressed'
    ];
    if (finalSkip.some(p => reviewText.toLowerCase().includes(p.toLowerCase()))) return;
    if (reviewText.length < 20) return;

    // Content-based deduplication
    const fingerprint = reviewText.substring(0, 80).toLowerCase().replace(/\s+/g, '');
    if (seenContent.has(fingerprint)) return;
    seenContent.add(fingerprint);

    parsed.push({
      json: {
        hotel_name: hotelName,
        platform: platform,
        review_text: reviewText,
        reviewer: reviewer,
        review_date: reviewDate,
        google_rating: rating,
        review_id: url + '_' + j,
        source_url: url
      }
    });
  });
});

return parsed.length > 0
  ? parsed
  : [{ json: { skipped: true, message: 'No review content found' } }];

