const items = $input.all();
const results = [];
const seenFingerprints = new Set();

const validItems = items.filter(item => !item.json.skipped);

if (validItems.length === 0) {
  return [{ json: { skipped: true, message: 'No reviews after normalization' } }];
}

validItems.forEach((item, i) => {
  const d = item.json;
  const review = d.reviews || d;
  const placeInfo = d.place_info || {};

  const isGoogleOrTA = !!d.reviews || 
                       !!d.place_info || 
                       (d.platform === 'Google Maps') ||
                       (d.platform === 'TripAdvisor');

  let reviewText = '';
  let reviewer = 'Anonymous';
  let reviewDate = '';
  let rating = null;
  let hotelName = '';
  let platform = '';
  let reviewId = '';
  let sourceUrl = '';

  if (isGoogleOrTA) {
    reviewText = review.snippet ||
                 review.extracted_snippet?.original ||
                 review.extracted_snippet?.translated ||
                 review.text ||
                 d.review_text || '';
    reviewer = review.user?.name ||
               review.username ||
               d.reviewer ||
               'Anonymous';
    reviewDate = review.iso_date ||
                 review.date ||
                 review.published_date ||
                 d.review_date || '';
    rating = review.rating ||
             d.rating ||
             d.google_rating ||
             null;
    hotelName = d.hotel_name ||
                placeInfo.title ||
                $('Read Hotels').item.json.hotel_name ||
                'Unknown';
    platform = d.platform ||
               (placeInfo.type === 'tripadvisor' ? 'TripAdvisor' : 'Google Maps');
    reviewId = review.review_id ||
               d.review_id ||
               (hotelName + '_' + reviewer + '_' + reviewDate);
    sourceUrl = d.source_url || '';
  } else {
    reviewText = d.review_text || '';
    reviewer = d.reviewer || 'Anonymous';
    reviewDate = d.review_date || '';
    rating = d.google_rating || d.rating || null;
    hotelName = d.hotel_name || $('Read Hotels').item.json.hotel_name || '';
    platform = d.platform || 'Web';
    reviewId = d.review_id || (hotelName + '_' + i);
    sourceUrl = d.source_url || '';
  }

  // Skip empty or too short
  if (!reviewText || reviewText.trim().length < 10) return;

  // Skip Excel errors
  if (reviewText.trim().startsWith('#ERROR')) return;

  // Skip navigation/promotional content
  const skipContent = [
    'Low rates',
    'Find cheaper',
    "We'll refund the difference",
    'Golfe of Tunis hotel reviews',
    'Grand Tunis hotel reviews',
    'Tunis Governorate hotel reviews'
  ];
  if (skipContent.some(p => reviewText.includes(p))) return;

  // Clean reviewer name
  reviewer = reviewer
    .replace(/\n.*/s, '')
    .replace(/\s{2,}/g, ' ')
    .trim();

  // Clean review text
  reviewText = reviewText
    .replace(/^•\s*Submitted from a mobile device\s*/g, '')
    .replace(/\s{2,}/g, ' ')
    .trim()
    .replace(/^\d+\.\d+\s+/, '')
    .replace(/^\d+\s+/, '')
    .trim();

  // Skip if text is just hotel name repeated
  const hotelNameLower = hotelName.toLowerCase();
  const textLower = reviewText.toLowerCase().replace(/\s+/g, ' ').trim();
  if (textLower === hotelNameLower || 
      textLower === (hotelNameLower + ' ' + hotelNameLower) ||
      textLower === (hotelNameLower + ' ' + hotelNameLower + ' ' + hotelNameLower)) return;

  // Fix Excel serial date
  if (reviewDate && String(reviewDate).match(/^\d{5}\.?\d*$/)) {
    const excelEpoch = new Date(1900, 0, 1);
    reviewDate = new Date(
      excelEpoch.getTime() + (parseFloat(reviewDate) - 2) * 86400000
    ).toISOString().split('T')[0];
  }

  // Normalize rating to /5 scale
  if (rating && parseFloat(rating) > 5) {
    rating = (parseFloat(rating) / 2).toFixed(1);
  }

  // Content-based deduplication
  const fingerprint = reviewText.substring(0, 100).toLowerCase().replace(/\s+/g, '');
  if (seenFingerprints.has(fingerprint)) return;
  seenFingerprints.add(fingerprint);

  results.push({
    json: {
      hotel_name: hotelName,
      platform: platform,
      reviewer: reviewer,
      review_date: reviewDate,
      review_text: reviewText,
      rating: rating ? parseFloat(rating) : null,
      review_id: String(reviewId),
      source_url: sourceUrl
    }
  });
});

return results.length > 0
  ? results
  : [{ json: { skipped: true, message: 'No reviews after normalization' } }];

const incoming = $('Normalize Reviews').all();
const logged = $('Read Logged IDs').all();

const existingIds = new Set(
  logged
    .map(item => String(item.json.review_id || '').trim())
    .filter(Boolean)
);

const newReviews = incoming.filter(item => {
  if (item.json.skipped) return false;
  const id = String(item.json.review_id || '').trim();
  const text = item.json.review_text || '';
  if (!text.trim()) return false;
  const metadataPatterns = [
    'Own or manage this property',
    'Claim your listing',
    'View prices for your travel dates',
    'Updated 2026',
    'Tripadvisor LLC makes no guarantees',
    'version of our website'
  ];
  if (metadataPatterns.some(p => text.includes(p))) return false;
  return id && !existingIds.has(id);
});

if (newReviews.length === 0) {
  return [{ json: { skipped: true, message: 'No new reviews' } }];
}

return newReviews;

const llmItems = $input.all();
const results = [];

for (let i = 0; i < llmItems.length; i++) {
  const llmItem = llmItems[i];
  const originalItem = $('Filter New Reviews Only').all()[i]?.json || {};

  const raw = llmItem.json.choices[0].message.content;
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  let sentiment = {};
  try {
    sentiment = JSON.parse(cleaned);
  } catch(e) {
    sentiment = {
      sentiment: 'unknown',
      score: 0,
      key_issue: 'Parse error',
      requires_response: false
    };
  }

  results.push({
    json: {
      hotel_name: originalItem.hotel_name,
      platform: originalItem.platform,
      reviewer: originalItem.reviewer,
      review_date: originalItem.review_date,
      review_text: originalItem.review_text,
      rating: originalItem.rating,
      review_id: originalItem.review_id,
      source_url: originalItem.source_url,
      sentiment: sentiment.sentiment,
      llm_score: sentiment.score,
      key_issue: sentiment.key_issue,
      requires_response: sentiment.requires_response
    }
  });
}

return results;

const items = $('Extract Sentiment').all();
const now = new Date();
const weekNumber = Math.ceil(
  (Math.floor((now - new Date(now.getFullYear(), 0, 1)) / 86400000) + 1) / 7
);
const weekLabel = now.getFullYear() + '-W' + String(weekNumber).padStart(2, '0');

const stats = {
  positive: 0, neutral: 0, negative: 0, total: 0,
  ratings: [], issues: {}
};

items.forEach(item => {
  const s = item.json.sentiment;
  stats.total++;
  if (s === 'positive') stats.positive++;
  else if (s === 'neutral') stats.neutral++;
  else if (s === 'negative') stats.negative++;
  if (item.json.rating) stats.ratings.push(parseFloat(item.json.rating));
  const issue = item.json.key_issue;
  if (issue && issue.trim()) {
    stats.issues[issue] = (stats.issues[issue] || 0) + 1;
  }
});

const avgRating = stats.ratings.length
  ? (stats.ratings.reduce((a, b) => a + b, 0) / stats.ratings.length).toFixed(1)
  : null;

const topIssue = Object.entries(stats.issues)
  .sort((a, b) => b[1] - a[1])[0]?.[0] || '';

return [{
  json: {
    week: weekLabel,
    hotel_name: items[0]?.json.hotel_name || $('Read Hotels').item.json.hotel_name,
    total_reviews: stats.total,
    positive: stats.positive,
    neutral: stats.neutral,
    negative: stats.negative,
    avg_rating: avgRating,
    top_issue: topIssue,
    run_timestamp: now.toISOString()
  }
}];
